"use strict";
import { BigNumber, Contract } from "ethers";
import { FeeAmount, Pool, Route, computePoolAddress } from "@uniswap/v3-sdk";
import { CurrencyAmount, Token, TradeType } from "@uniswap/sdk-core";
import JSBI from "jsbi";
import { RPC_PROVIDERS } from "constants/providers";
import { ClassicTrade, QuoteMethod } from "state/routing/types";
import { getChainInfo } from "uniswap/src/features/chains/chainInfo";
import { UniverseChainId } from "uniswap/src/features/chains/types";
const MST_FACTORY = "0x8D5c080545768aBCbFEe3F60Eab68cC17b7B3254";
const MST_QUOTER_V2 = "0x2Ad8a328ddf9398D9CBa50dfb487a77dfc44D1C9";
const WMST_ADDRESS = "0x93199C4a0b7F5807E627E9A580b1ABF684Ae85E9";
const POOL_ABI = [
  "function slot0() view returns (uint160 sqrtPriceX96, int24 tick, uint16 observationIndex, uint16 observationCardinality, uint16 observationCardinalityNext, uint8 feeProtocol, bool unlocked)",
  "function liquidity() view returns (uint128)"
];
const QUOTER_ABI = [
  "function quoteExactInputSingle(tuple(address tokenIn, address tokenOut, uint256 amountIn, uint24 fee, uint160 sqrtPriceLimitX96) params) returns (uint256 amountOut, uint160 sqrtPriceX96After, uint32 initializedTicksCrossed, uint256 gasEstimate)",
  "function quoteExactOutputSingle(tuple(address tokenIn, address tokenOut, uint256 amount, uint24 fee, uint160 sqrtPriceLimitX96) params) returns (uint256 amountIn, uint160 sqrtPriceX96After, uint32 initializedTicksCrossed, uint256 gasEstimate)"
];
const FEE_TIERS = [FeeAmount.MEDIUM, FeeAmount.LOW, FeeAmount.LOWEST, FeeAmount.HIGH];
function resolveTokenAddress(addr) {
  if (addr.length < 10 || addr.toLowerCase() === "0xeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeee") {
    return WMST_ADDRESS;
  }
  return addr;
}
export async function getMSTDirectQuote(args) {
  const {
    tokenInAddress,
    tokenInChainId,
    tokenInDecimals,
    tokenInSymbol,
    tokenOutAddress,
    tokenOutDecimals,
    tokenOutSymbol,
    amount,
    tradeType
  } = args;
  const provider = RPC_PROVIDERS[UniverseChainId.MstTestnet];
  if (!provider) {
    return null;
  }
  const resolvedIn = resolveTokenAddress(tokenInAddress);
  const resolvedOut = resolveTokenAddress(tokenOutAddress);
  const tokenIn = new Token(tokenInChainId, resolvedIn, tokenInDecimals, tokenInSymbol ?? "TOKEN");
  const tokenOut = new Token(tokenInChainId, resolvedOut, tokenOutDecimals, tokenOutSymbol ?? "TOKEN");
  if (tokenIn.equals(tokenOut)) {
    return null;
  }
  const quoter = new Contract(MST_QUOTER_V2, QUOTER_ABI, provider);
  for (const fee of FEE_TIERS) {
    try {
      const poolAddress = computePoolAddress({
        factoryAddress: MST_FACTORY,
        tokenA: tokenIn,
        tokenB: tokenOut,
        fee,
        chainId: getChainInfo(tokenInChainId).sdkId
      });
      const poolContract = new Contract(poolAddress, POOL_ABI, provider);
      const [slot0, liquidity] = await Promise.all([poolContract.slot0(), poolContract.liquidity()]);
      if (!slot0?.sqrtPriceX96 || BigNumber.from(slot0.sqrtPriceX96).eq(0)) {
        continue;
      }
      let inRaw;
      let outRaw;
      if (tradeType === TradeType.EXACT_INPUT) {
        const result = await quoter.callStatic.quoteExactInputSingle({
          tokenIn: resolvedIn,
          tokenOut: resolvedOut,
          amountIn: amount,
          fee,
          sqrtPriceLimitX96: 0
        });
        inRaw = amount;
        outRaw = result.amountOut.toString();
      } else {
        const result = await quoter.callStatic.quoteExactOutputSingle({
          tokenIn: resolvedIn,
          tokenOut: resolvedOut,
          amount,
          fee,
          sqrtPriceLimitX96: 0
        });
        inRaw = result.amountIn.toString();
        outRaw = amount;
      }
      const [sortedT0, sortedT1] = tokenIn.sortsBefore(tokenOut) ? [tokenIn, tokenOut] : [tokenOut, tokenIn];
      const v3Pool = new Pool(
        sortedT0,
        sortedT1,
        fee,
        JSBI.BigInt(slot0.sqrtPriceX96.toString()),
        JSBI.BigInt(liquidity.toString()),
        slot0.tick
      );
      const route = new Route([v3Pool], tokenIn, tokenOut);
      const inputAmount = CurrencyAmount.fromRawAmount(tokenIn, JSBI.BigInt(inRaw));
      const outputAmount = CurrencyAmount.fromRawAmount(tokenOut, JSBI.BigInt(outRaw));
      const approveInfo = { needsApprove: false };
      return new ClassicTrade({
        v2Routes: [],
        v3Routes: [{ routev3: route, inputAmount, outputAmount }],
        tradeType,
        quoteMethod: QuoteMethod.CLIENT_SIDE_FALLBACK,
        approveInfo
      });
    } catch {
      continue;
    }
  }
  return null;
}
